"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[1645],{6768(t,e,d){d.r(e),d.d(e,{comp:()=>n,data:()=>o});var a=d(641);const s={},n=(0,d(6262).A)(s,[["render",function(t,e){return(0,a.uX)(),(0,a.CE)("div",null,[...e[0]||(e[0]=[(0,a.Fv)('<h1 id="database-schema" tabindex="-1"><a class="header-anchor" href="#database-schema"><span>Database Schema</span></a></h1><p>The plugin creates <strong>16 custom tables</strong> plus uses standard WP / WC tables. All prefixed by your <code>$wpdb-&gt;prefix</code> (typically <code>wp_</code>).</p><p>Schema version: <strong>1.5.0</strong></p><h2 id="table-index" tabindex="-1"><a class="header-anchor" href="#table-index"><span>Table index</span></a></h2><table><thead><tr><th>Table</th><th>Columns</th><th>Indexes</th><th>Purpose</th></tr></thead><tbody><tr><td><code>wkafw_auctions</code></td><td>22</td><td>5</td><td>Core auction records</td></tr><tr><td><code>wkafw_bids</code></td><td>10</td><td>7</td><td>Every bid placed</td></tr><tr><td><code>wkafw_proxy_bids</code></td><td>6</td><td>2</td><td>Proxy / max-bid storage</td></tr><tr><td><code>wkafw_watchlist</code></td><td>4</td><td>2</td><td>User → auction watch links</td></tr><tr><td><code>wkafw_auction_logs</code></td><td>8</td><td>5</td><td>Lifecycle event log</td></tr><tr><td><code>wkafw_disputes</code></td><td>8</td><td>3</td><td>Buyer-filed disputes</td></tr><tr><td><code>wkafw_events</code></td><td>11</td><td>4</td><td>Event grouping</td></tr><tr><td><code>wkafw_event_lots</code></td><td>4</td><td>2</td><td>Event ↔ auction many-to-many</td></tr><tr><td><code>wkafw_event_registrations</code></td><td>5</td><td>2</td><td>Bidders registered for events</td></tr><tr><td><code>wkafw_messages</code></td><td>7</td><td>3</td><td>Buyer ↔ seller messages</td></tr><tr><td><code>wkafw_notifications</code></td><td>8</td><td>2</td><td>In-app notifications</td></tr><tr><td><code>wkafw_bid_packs</code></td><td>11</td><td>5</td><td>Penny-auction bid tokens</td></tr><tr><td><code>wkafw_auction_seats</code></td><td>6</td><td>3</td><td>Seated-auction paddle assignment</td></tr><tr><td><code>wkafw_vendor_commissions</code></td><td>13</td><td>7</td><td>Multi-vendor revenue split</td></tr><tr><td><code>wkafw_vendor_ratings</code></td><td>7</td><td>4</td><td>Buyer-rated seller scores</td></tr><tr><td><code>wkwc_wallet_transactions</code></td><td>10</td><td>4</td><td>Wallet ledger (submodule)</td></tr></tbody></table><h2 id="key-tables-in-detail" tabindex="-1"><a class="header-anchor" href="#key-tables-in-detail"><span>Key tables in detail</span></a></h2><h3 id="wkafw-auctions" tabindex="-1"><a class="header-anchor" href="#wkafw-auctions"><span><code>wkafw_auctions</code></span></a></h3><p>The central table — one row per auction.</p><table><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td><code>id</code></td><td>BIGINT(20) UNSIGNED</td><td>PK</td></tr><tr><td><code>product_id</code></td><td>BIGINT(20) UNSIGNED</td><td>FK → <code>wp_posts.ID</code></td></tr><tr><td><code>auction_type</code></td><td>VARCHAR(20)</td><td>standard / reverse / sealed / proxy / silent / charity / penny / dutch / seated / unique-bid</td></tr><tr><td><code>start_price</code></td><td>DECIMAL(19,4)</td><td>Opening bid</td></tr><tr><td><code>reserve_price</code></td><td>DECIMAL(19,4)</td><td>Hidden minimum</td></tr><tr><td><code>buy_now_price</code></td><td>DECIMAL(19,4)</td><td>BIN price (0 = disabled)</td></tr><tr><td><code>bid_increment</code></td><td>DECIMAL(19,4)</td><td>Required step amount</td></tr><tr><td><code>increment_type</code></td><td>VARCHAR(20)</td><td>fixed / variable / percentage</td></tr><tr><td><code>variable_increments</code></td><td>LONGTEXT</td><td>JSON tier table</td></tr><tr><td><code>start_date</code> / <code>end_date</code></td><td>DATETIME</td><td>Auction window</td></tr><tr><td><code>original_end_date</code></td><td>DATETIME</td><td>Pre-anti-snipe end (for reporting)</td></tr><tr><td><code>status</code></td><td>VARCHAR(20)</td><td>scheduled / active / paused / ended / paid / failed / cancelled</td></tr><tr><td><code>anti_snipe_window</code> / <code>anti_snipe_extension</code></td><td>INT(11)</td><td>Soft-close config</td></tr><tr><td><code>max_extension</code></td><td>INT(11)</td><td>Cumulative extension cap (0 = unlimited)</td></tr><tr><td><code>total_extensions</code></td><td>INT(11)</td><td>Counter</td></tr><tr><td><code>current_price</code></td><td>DECIMAL(19,4)</td><td>Live high bid</td></tr><tr><td><code>bid_count</code></td><td>INT(11)</td><td>Counter</td></tr><tr><td><code>item_condition</code></td><td>VARCHAR(20)</td><td>new / like_new / used / refurbished / for_parts</td></tr><tr><td><code>created_at</code> / <code>updated_at</code></td><td>DATETIME</td><td>Standard timestamps</td></tr></tbody></table><p><strong>Indexes:</strong> <code>id</code> (PK), <code>product_id</code>, <code>status</code>, <code>start_date</code>, <code>end_date</code></p><h3 id="wkafw-bids" tabindex="-1"><a class="header-anchor" href="#wkafw-bids"><span><code>wkafw_bids</code></span></a></h3><p>Every bid placed.</p><table><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td><code>id</code></td><td>BIGINT(20) UNSIGNED</td><td>PK</td></tr><tr><td><code>auction_id</code></td><td>BIGINT(20) UNSIGNED</td><td>FK → <code>wkafw_auctions.id</code></td></tr><tr><td><code>user_id</code></td><td>BIGINT(20) UNSIGNED</td><td>FK → <code>wp_users.ID</code></td></tr><tr><td><code>bid_amount</code></td><td>DECIMAL(19,4)</td><td>The amount</td></tr><tr><td><code>bid_type</code></td><td>VARCHAR(20)</td><td>manual / proxy / absentee / auto</td></tr><tr><td><code>ip_address</code></td><td>VARCHAR(45)</td><td>IPv4 / IPv6</td></tr><tr><td><code>user_agent</code></td><td>VARCHAR(255)</td><td>Browser UA</td></tr><tr><td><code>is_anonymous</code></td><td>TINYINT(1)</td><td>0 / 1</td></tr><tr><td><code>status</code></td><td>VARCHAR(20)</td><td>active / retracted / fraudulent / outbid</td></tr><tr><td><code>created_at</code></td><td>DATETIME</td><td>When placed (UTC)</td></tr></tbody></table><p><strong>Indexes:</strong> <code>id</code> (PK), <code>auction_id</code>, <code>user_id</code>, <code>bid_amount</code>, <code>created_at</code>, <code>status</code>, <code>auction_status_amount</code> (composite)</p><h3 id="wkafw-watchlist" tabindex="-1"><a class="header-anchor" href="#wkafw-watchlist"><span><code>wkafw_watchlist</code></span></a></h3><table><thead><tr><th>Column</th><th>Type</th></tr></thead><tbody><tr><td><code>id</code></td><td>BIGINT(20) UNSIGNED</td></tr><tr><td><code>auction_id</code></td><td>BIGINT(20) UNSIGNED</td></tr><tr><td><code>user_id</code></td><td>BIGINT(20) UNSIGNED</td></tr><tr><td><code>created_at</code></td><td>DATETIME</td></tr></tbody></table><p><strong>Unique index:</strong> <code>(auction_id, user_id)</code> — one watch per user per auction.</p><h3 id="wkafw-proxy-bids" tabindex="-1"><a class="header-anchor" href="#wkafw-proxy-bids"><span><code>wkafw_proxy_bids</code></span></a></h3><table><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td><code>id</code></td><td>BIGINT(20) UNSIGNED</td><td>PK</td></tr><tr><td><code>auction_id</code></td><td>BIGINT(20) UNSIGNED</td><td>FK</td></tr><tr><td><code>user_id</code></td><td>BIGINT(20) UNSIGNED</td><td>FK</td></tr><tr><td><code>max_amount</code></td><td>DECIMAL(19,4)</td><td>The user&#39;s secret max bid</td></tr><tr><td><code>is_active</code></td><td>TINYINT(1)</td><td>0 = absentee (pre-bid before auction starts)</td></tr><tr><td><code>created_at</code></td><td>DATETIME</td><td></td></tr></tbody></table><h3 id="wkafw-auction-logs" tabindex="-1"><a class="header-anchor" href="#wkafw-auction-logs"><span><code>wkafw_auction_logs</code></span></a></h3><p>The general activity log (per-auction events).</p><table><thead><tr><th>Column</th><th>Type</th></tr></thead><tbody><tr><td><code>id</code></td><td>BIGINT(20)</td></tr><tr><td><code>auction_id</code></td><td>BIGINT(20)</td></tr><tr><td><code>user_id</code></td><td>BIGINT(20)</td></tr><tr><td><code>action</code></td><td>VARCHAR(50) — e.g. <code>bid_placed</code>, <code>started</code>, <code>extended</code>, <code>won</code></td></tr><tr><td><code>details</code></td><td>LONGTEXT — JSON payload</td></tr><tr><td><code>ip_address</code></td><td>VARCHAR(45)</td></tr><tr><td><code>user_agent</code></td><td>VARCHAR(512)</td></tr><tr><td><code>created_at</code></td><td>DATETIME</td></tr></tbody></table><p>This is <strong>separate from</strong> the bid hash-chain (<code>Wkafw_Bid_Audit_Chain</code>) which uses an in-memory + file-backed structure.</p><h3 id="wkwc-wallet-transactions" tabindex="-1"><a class="header-anchor" href="#wkwc-wallet-transactions"><span><code>wkwc_wallet_transactions</code></span></a></h3><p>Wallet ledger (provided by submodule).</p><table><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td><code>id</code></td><td>BIGINT(20)</td><td>PK</td></tr><tr><td><code>order_id</code></td><td>VARCHAR(250)</td><td>Source order ID (top-up) or null</td></tr><tr><td><code>reference</code></td><td>VARCHAR(100)</td><td>Unique transaction reference</td></tr><tr><td><code>sender</code></td><td>INT(10)</td><td>For transfers — sender user_id</td></tr><tr><td><code>customer</code></td><td>INT(10)</td><td>The wallet owner</td></tr><tr><td><code>amount</code></td><td>VARCHAR(50)</td><td>(stored as string for currency precision)</td></tr><tr><td><code>transaction_type</code></td><td>VARCHAR(10)</td><td><code>cr</code> (credit) / <code>dr</code> (debit)</td></tr><tr><td><code>transaction_date</code></td><td>DATETIME</td><td></td></tr><tr><td><code>transaction_status</code></td><td>VARCHAR(10)</td><td><code>completed</code> / <code>pending</code> / <code>failed</code></td></tr><tr><td><code>transaction_note</code></td><td>VARCHAR(250)</td><td></td></tr></tbody></table><p>Balance is <strong>derived</strong> from this table — not stored. See <a href="/wallet-system.html" target="_blank" rel="noopener noreferrer">Wallet System</a>.</p><h3 id="wkafw-vendor-commissions" tabindex="-1"><a class="header-anchor" href="#wkafw-vendor-commissions"><span><code>wkafw_vendor_commissions</code></span></a></h3><p>Multi-vendor revenue split.</p><table><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td><code>id</code></td><td>BIGINT(20) UNSIGNED</td><td>PK</td></tr><tr><td><code>vendor_id</code></td><td>BIGINT(20) UNSIGNED</td><td>FK → user (the vendor)</td></tr><tr><td><code>auction_id</code></td><td>BIGINT(20) UNSIGNED</td><td>FK</td></tr><tr><td><code>order_id</code></td><td>BIGINT(20) UNSIGNED</td><td>FK → WC order</td></tr><tr><td><code>total_amount</code></td><td>DECIMAL(19,4)</td><td>Winning bid amount</td></tr><tr><td><code>commission_rate</code></td><td>DECIMAL(6,3)</td><td>Platform&#39;s %</td></tr><tr><td><code>commission_amount</code></td><td>DECIMAL(19,4)</td><td>Platform&#39;s earnings</td></tr><tr><td><code>vendor_earning</code></td><td>DECIMAL(19,4)</td><td>Vendor&#39;s net</td></tr><tr><td><code>adapter_slug</code></td><td>VARCHAR(32)</td><td>wcfm / dokan / wc_vendors / yith / native</td></tr><tr><td><code>native_row_id</code></td><td>BIGINT(20)</td><td>Cross-reference to multi-vendor plugin&#39;s own commission row</td></tr><tr><td><code>status</code></td><td>VARCHAR(20)</td><td>pending / paid / cancelled</td></tr><tr><td><code>created_at</code> / <code>updated_at</code></td><td>DATETIME</td><td></td></tr></tbody></table><p><strong>Unique index:</strong> <code>(auction_id, vendor_id)</code> — one commission per vendor per auction.</p><h2 id="relationships" tabindex="-1"><a class="header-anchor" href="#relationships"><span>Relationships</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">wp_users (WP)</span>\n<span class="line">   ↓ 1:N</span>\n<span class="line">wkafw_bids ───► wkafw_auctions ◄─── wkafw_proxy_bids</span>\n<span class="line">                     │</span>\n<span class="line">                     ├─► wkafw_watchlist</span>\n<span class="line">                     ├─► wkafw_auction_logs</span>\n<span class="line">                     ├─► wkafw_disputes</span>\n<span class="line">                     ├─► wkafw_event_lots ─► wkafw_events</span>\n<span class="line">                     ├─► wkafw_messages</span>\n<span class="line">                     ├─► wkafw_auction_seats (seated)</span>\n<span class="line">                     ├─► wkafw_bid_packs (penny — by user)</span>\n<span class="line">                     └─► wkafw_vendor_commissions ─► wp_users (vendor)</span>\n<span class="line">                                                    └─► wp_wc_orders (HPOS) or wp_posts</span>\n<span class="line"></span>\n<span class="line">wp_users</span>\n<span class="line">   ↓ 1:N</span>\n<span class="line">wkwc_wallet_transactions</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="query-patterns" tabindex="-1"><a class="header-anchor" href="#query-patterns"><span>Query patterns</span></a></h2><h3 id="count-active-auctions" tabindex="-1"><a class="header-anchor" href="#count-active-auctions"><span>Count active auctions</span></a></h3><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code><span class="line"><span class="token keyword">SELECT</span> <span class="token function">COUNT</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span> <span class="token keyword">FROM</span> wp_wkafw_auctions <span class="token keyword">WHERE</span> <span class="token keyword">status</span> <span class="token operator">=</span> <span class="token string">&#39;active&#39;</span><span class="token punctuation">;</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="user-s-wallet-balance" tabindex="-1"><a class="header-anchor" href="#user-s-wallet-balance"><span>User&#39;s wallet balance</span></a></h3><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code><span class="line"><span class="token keyword">SELECT</span></span>\n<span class="line">  <span class="token function">SUM</span><span class="token punctuation">(</span><span class="token keyword">CASE</span> <span class="token keyword">WHEN</span> transaction_type<span class="token operator">=</span><span class="token string">&#39;cr&#39;</span> <span class="token keyword">THEN</span> CAST<span class="token punctuation">(</span>amount <span class="token keyword">AS</span> <span class="token keyword">DECIMAL</span><span class="token punctuation">(</span><span class="token number">19</span><span class="token punctuation">,</span><span class="token number">4</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token keyword">ELSE</span> <span class="token number">0</span> <span class="token keyword">END</span><span class="token punctuation">)</span> <span class="token operator">-</span></span>\n<span class="line">  <span class="token function">SUM</span><span class="token punctuation">(</span><span class="token keyword">CASE</span> <span class="token keyword">WHEN</span> transaction_type<span class="token operator">=</span><span class="token string">&#39;dr&#39;</span> <span class="token keyword">THEN</span> CAST<span class="token punctuation">(</span>amount <span class="token keyword">AS</span> <span class="token keyword">DECIMAL</span><span class="token punctuation">(</span><span class="token number">19</span><span class="token punctuation">,</span><span class="token number">4</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token keyword">ELSE</span> <span class="token number">0</span> <span class="token keyword">END</span><span class="token punctuation">)</span></span>\n<span class="line"><span class="token keyword">FROM</span> wp_wkwc_wallet_transactions</span>\n<span class="line"><span class="token keyword">WHERE</span> customer <span class="token operator">=</span> ? <span class="token operator">AND</span> transaction_status <span class="token operator">=</span> <span class="token string">&#39;completed&#39;</span><span class="token punctuation">;</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="top-bidders-lifetime" tabindex="-1"><a class="header-anchor" href="#top-bidders-lifetime"><span>Top bidders (lifetime)</span></a></h3><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code><span class="line"><span class="token keyword">SELECT</span> u<span class="token punctuation">.</span>display_name<span class="token punctuation">,</span> <span class="token function">COUNT</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> bid_count</span>\n<span class="line"><span class="token keyword">FROM</span> wp_wkafw_bids b</span>\n<span class="line"><span class="token keyword">JOIN</span> wp_users u <span class="token keyword">ON</span> b<span class="token punctuation">.</span>user_id <span class="token operator">=</span> u<span class="token punctuation">.</span>ID</span>\n<span class="line"><span class="token keyword">WHERE</span> b<span class="token punctuation">.</span><span class="token keyword">status</span> <span class="token operator">=</span> <span class="token string">&#39;active&#39;</span></span>\n<span class="line"><span class="token keyword">GROUP</span> <span class="token keyword">BY</span> b<span class="token punctuation">.</span>user_id</span>\n<span class="line"><span class="token keyword">ORDER</span> <span class="token keyword">BY</span> bid_count <span class="token keyword">DESC</span></span>\n<span class="line"><span class="token keyword">LIMIT</span> <span class="token number">10</span><span class="token punctuation">;</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="bid-history-for-a-specific-auction" tabindex="-1"><a class="header-anchor" href="#bid-history-for-a-specific-auction"><span>Bid history for a specific auction</span></a></h3><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code><span class="line"><span class="token keyword">SELECT</span> b<span class="token punctuation">.</span><span class="token operator">*</span><span class="token punctuation">,</span> u<span class="token punctuation">.</span>display_name</span>\n<span class="line"><span class="token keyword">FROM</span> wp_wkafw_bids b</span>\n<span class="line"><span class="token keyword">JOIN</span> wp_users u <span class="token keyword">ON</span> b<span class="token punctuation">.</span>user_id <span class="token operator">=</span> u<span class="token punctuation">.</span>ID</span>\n<span class="line"><span class="token keyword">WHERE</span> b<span class="token punctuation">.</span>auction_id <span class="token operator">=</span> ? <span class="token operator">AND</span> b<span class="token punctuation">.</span><span class="token keyword">status</span> <span class="token operator">=</span> <span class="token string">&#39;active&#39;</span></span>\n<span class="line"><span class="token keyword">ORDER</span> <span class="token keyword">BY</span> b<span class="token punctuation">.</span>created_at <span class="token keyword">DESC</span><span class="token punctuation">;</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="performance" tabindex="-1"><a class="header-anchor" href="#performance"><span>Performance</span></a></h2><p>Every plugin query uses indexed columns. Common access patterns are O(log N) on the relevant index.</p><p>For very large databases (1M+ bids):</p><ul><li>Add a composite index on <code>(auction_id, status, created_at)</code> for bid history pagination</li><li>Partition <code>wkafw_auction_logs</code> by <code>created_at</code> (monthly partitions)</li><li>Archive old auctions (status <code>paid</code> / <code>failed</code> older than 1 year) to a separate table</li></ul><p>The plugin doesn&#39;t auto-partition or archive — operator&#39;s responsibility.</p><h2 id="migrations" tabindex="-1"><a class="header-anchor" href="#migrations"><span>Migrations</span></a></h2><p>Schema changes are versioned. On plugin upgrade, <code>Wkafw_Installer::maybe_migrate_db()</code> checks the stored version against the code version and runs incremental migrations.</p><table><thead><tr><th>Stored option</th><th>Effect</th></tr></thead><tbody><tr><td><code>wkafw_db_version</code></td><td>Current schema version</td></tr><tr><td><code>wkafw_db_migrations_failed</code></td><td>List of failed migrations (for retry)</td></tr></tbody></table><p>Manual migration: <strong>Tools → Database → Re-run migrations</strong> (<a href="/admin-tools.html#database" target="_blank" rel="noopener noreferrer">Tools →</a>).</p><h2 id="hpos" tabindex="-1"><a class="header-anchor" href="#hpos"><span>HPOS</span></a></h2><p>Order data is queried from:</p><table><thead><tr><th>Setting</th><th>Tables used</th></tr></thead><tbody><tr><td>HPOS active</td><td><code>wp_wc_orders</code>, <code>wp_wc_orders_meta</code></td></tr><tr><td>HPOS inactive (legacy)</td><td><code>wp_posts</code> (post_type=<code>shop_order</code>) + <code>wp_postmeta</code></td></tr></tbody></table><p>The plugin auto-detects via <code>\\Automattic\\WooCommerce\\Utilities\\OrderUtil::custom_orders_table_usage_is_enabled()</code>.</p><h2 id="backup-recommendations" tabindex="-1"><a class="header-anchor" href="#backup-recommendations"><span>Backup recommendations</span></a></h2><ul><li><strong>Daily</strong>: full DB dump including all <code>wkafw_*</code> and <code>wkwc_wallet_*</code> tables</li><li><strong>Hourly</strong>: <code>wkafw_bids</code> + <code>wkafw_auction_logs</code> (for audit recovery)</li><li><strong>Real-time</strong>: replicate to a read-only standby (for high-availability sites)</li></ul><p>The plugin&#39;s data is <strong>not</strong> recoverable from WP exports — use mysqldump or your hosting provider&#39;s backup tool.</p><h2 id="see-also" tabindex="-1"><a class="header-anchor" href="#see-also"><span>See also</span></a></h2><ul><li><a href="/hooks-filters.html" target="_blank" rel="noopener noreferrer">Hooks &amp; Filters</a> — actions / filters reference</li><li><a href="/options.html" target="_blank" rel="noopener noreferrer">Options Reference</a> — all 132 plugin options</li><li><a href="/admin-tools.html#database" target="_blank" rel="noopener noreferrer">Tools → Database</a> — admin migration / repair tools</li></ul>',60)])])}]]),o=JSON.parse('{"path":"/database.html","title":"Database Schema","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Table index","slug":"table-index","link":"#table-index","children":[]},{"level":2,"title":"Key tables in detail","slug":"key-tables-in-detail","link":"#key-tables-in-detail","children":[{"level":3,"title":"wkafw_auctions","slug":"wkafw-auctions","link":"#wkafw-auctions","children":[]},{"level":3,"title":"wkafw_bids","slug":"wkafw-bids","link":"#wkafw-bids","children":[]},{"level":3,"title":"wkafw_watchlist","slug":"wkafw-watchlist","link":"#wkafw-watchlist","children":[]},{"level":3,"title":"wkafw_proxy_bids","slug":"wkafw-proxy-bids","link":"#wkafw-proxy-bids","children":[]},{"level":3,"title":"wkafw_auction_logs","slug":"wkafw-auction-logs","link":"#wkafw-auction-logs","children":[]},{"level":3,"title":"wkwc_wallet_transactions","slug":"wkwc-wallet-transactions","link":"#wkwc-wallet-transactions","children":[]},{"level":3,"title":"wkafw_vendor_commissions","slug":"wkafw-vendor-commissions","link":"#wkafw-vendor-commissions","children":[]}]},{"level":2,"title":"Relationships","slug":"relationships","link":"#relationships","children":[]},{"level":2,"title":"Query patterns","slug":"query-patterns","link":"#query-patterns","children":[{"level":3,"title":"Count active auctions","slug":"count-active-auctions","link":"#count-active-auctions","children":[]},{"level":3,"title":"User\'s wallet balance","slug":"user-s-wallet-balance","link":"#user-s-wallet-balance","children":[]},{"level":3,"title":"Top bidders (lifetime)","slug":"top-bidders-lifetime","link":"#top-bidders-lifetime","children":[]},{"level":3,"title":"Bid history for a specific auction","slug":"bid-history-for-a-specific-auction","link":"#bid-history-for-a-specific-auction","children":[]}]},{"level":2,"title":"Performance","slug":"performance","link":"#performance","children":[]},{"level":2,"title":"Migrations","slug":"migrations","link":"#migrations","children":[]},{"level":2,"title":"HPOS","slug":"hpos","link":"#hpos","children":[]},{"level":2,"title":"Backup recommendations","slug":"backup-recommendations","link":"#backup-recommendations","children":[]},{"level":2,"title":"See also","slug":"see-also","link":"#see-also","children":[]}],"git":{},"filePathRelative":"database.md"}')}}]);